let items=[];
try{
  const d=JSON.parse(text);
  items=(d&&d.data&&d.data.result)?d.data.result:(Array.isArray(d)?d:[]);
}catch(_){
  // Parse 'metric{labels} => value @[ts]' text format
  items=text.trim().split('\n').filter(Boolean).map(l=>{
    const valMatch=l.match(/=> ([\d.]+(?:e[+-]?\d+)?) @/);
    const val=valMatch?valMatch[1]:'0';
    const labels={};
    const labelStr=l.match(/\{([^}]*)\}/);
    if(labelStr){ labelStr[1].split(', ').forEach(p=>{ const [k,...v]=p.split('='); if(k) labels[k.trim()]=v.join('=').replace(/^\\?"?|\\?"?$/g,''); }); }
    const nameMatch=l.match(/^([^{\s]+)/);
    if(nameMatch) labels['__name__']=nameMatch[1];
    return {metric:labels, value:[null,val]};
  });
}

