const styles = `body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#0f172a;color:#e2e8f0;padding:16px;margin:0}h2{color:#fb923c;margin:0 0 8px;font-size:14px;text-transform:uppercase}p.sub{color:#475569;font-size:11px;margin:0 0 12px}table{width:100%;border-collapse:collapse;font-size:11px}th{background:#1e293b;color:#94a3b8;text-align:left;padding:8px;font-weight:600;border-bottom:1px solid #334155}td{padding:6px 8px;border-bottom:1px solid #1e293b;font-family:monospace;overflow:hidden}tr:hover td{background:#1e293b55}.val{color:#86efac;font-weight:bold}.err{color:#f87171}`;
try{
  const resp = pm.response.json();
  const txt = resp.result.content[0].text;
  let prom = txt;
  try{const p = JSON.parse(txt); prom = p.result || txt;}catch(e){}
  const lines = prom.split('\n').filter(l=>l.trim());
  let html = `<style>${styles}</style><h2>Bifrost Metrics</h2><p class=sub>${lines.length} series</p>`;
  if(lines.length){
    html += '<table><tr><th>Metric</th><th>Value</th></tr>';
    lines.slice(0,25).forEach(l=>{
      const m = l.match(/^(.+?)\s*=>\s*(.+?)\s*@/);
      if(m) html += `<tr><td>${m[1].substring(0,100)}</td><td class=val>${m[2]}</td></tr>`;
    });
    html += '</table>';
  }
  pm.visualizer.set(html);
}catch(e){pm.visualizer.set(`<style>${styles}</style><p class=err>Error: ${e.message}</p>`);}

